/**
 * Read historical metrics snapshots from metrics.jsonl.
 * @param {object} [options]
 * @param {number} [options.since] - Timestamp filter (ms)
 * @param {number} [options.limit=50] - Max entries to return
 * @returns {Array<object>}
 */
