  if (_rotating) {
    // Buffer writes during rotation to avoid losing data
    _rotateBuffer.push(JSON.stringify(record) + '\n');
  } else {
    fs.appendFileSync(LOG_FILE, JSON.stringify(record) + '\n', 'utf8');
  }
