    } catch (_) {}
  }

  const sweepResult = {
    sweep: 'user-insight',
    hasRecentOutput,
    hasRecentRequest,
    emitted,
    windowMinutes,
    timestamp: new Date().toISOString(),
  };

  logSweep(sweepResult);
  return sweepResult;
